// Merge AI analysis with rule-based detection
const aiResponse = $input.first().json;
let aiResult = {};

try {
  const content = aiResponse.content && aiResponse.content[0] && aiResponse.content[0].text;
  if (content) {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      aiResult = JSON.parse(jsonMatch[0]);
    }
  }
} catch (e) {
  // AI parse failed, stick with rule-based
}

// Get the original job data from the method detection node
const prevData = $('Detect Application Method').first().json;

let finalMethod = prevData.detected_method;
let finalConfidence = prevData.method_confidence;
let finalEmail = prevData.detected_email;
let finalPortalType = prevData.detected_portal_type;
let finalPortalUrl = prevData.detected_portal_url;

if (aiResult.confidence && aiResult.confidence > finalConfidence) {
  finalMethod = aiResult.method || finalMethod;
  finalConfidence = aiResult.confidence;
  if (aiResult.email_address && aiResult.email_address !== 'if email method or null' && aiResult.email_address !== null) {
    finalEmail = aiResult.email_address;
  }
  if (aiResult.portal_type && aiResult.portal_type !== 'if portal or null' && aiResult.portal_type !== null) {
    finalPortalType = aiResult.portal_type;
  }
}

return [{
  json: {
    ...prevData,
    detected_method: finalMethod,
    method_confidence: finalConfidence,
    detected_email: finalEmail,
    detected_portal_url: finalPortalUrl,
    detected_portal_type: finalPortalType,
    ai_analysis_used: true
  }
}];

// Pass through -- no AI needed (already high confidence)
const job = $input.first().json;
return [{ json: { ...job, ai_analysis_used: false } }];

